// Parse Strategist (Claude) response
const response = $input.first().json;
let strategyText = '';

if (response.content && Array.isArray(response.content)) {
  strategyText = response.content
    .filter(b => b.type === 'text')
    .map(b => b.text)
    .join('');
}

// Extract JSON from response
let strategy = {};
try {
  const jsonMatch = strategyText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    strategy = JSON.parse(jsonMatch[0]);
  }
} catch(e) {
  strategy = { 
    weekly_theme: strategyText.substring(0, 200),
    raw_response: strategyText,
    parse_error: e.message
  };
}

return [{ json: { strategy, raw_strategy: strategyText } }];

